def n_queens_count(n):
    def is_safe(board, row, col):
        for i in range(col):
            if board[row][i] == 1:
                return False
            if row + i < n and board[row + i][col] == 1:
                return False
            if row - i >= 0 and board[row - i][col] == 1:
                return False
        return True

    def solve_n_queens_util(board, col, n):
        if col >= n:
            return 1
        count = 0
        for i in range(n):
            if is_safe(board, i, col):
                board[i][col] = 1
                count += solve_n_queens_util(board, col + 1, n)
                board[i][col] = 0
        return count

    def solve_n_queens(n):
        board = [[0 for _ in range(n)] for _ in range(n)]
        return solve_n_queens_util(board, 0, n)

    return solve_n_queens(n)
